import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Game of Life - nextGeneration", () => {
  it.todo("should return an empty array when given an empty array (no living cells)");

  it.todo("Rule 1 (Underpopulation): a single live cell [(0,0)] dies → []");

  it.todo("Rule 1 (Underpopulation): two adjacent cells [(0,1), (1,1)] each have 1 neighbor and die → []");

  it.todo("Rule 2 (Survival): in row ### at y=0 with cell (1,-1), the center cell (1,1) has 3 neighbors and survives — next gen contains (1,1)");

  it.todo("Rule 3 (Overpopulation): in a full 3x3 grid, the center cell (1,1) has 4 neighbors and dies — (1,1) is not in next gen");

  it.todo("Rule 4 (Reproduction): L-shape [(0,2),(1,2),(0,1)] — dead cell (1,1) has exactly 3 neighbors and becomes alive — next gen contains (1,1)");

  it.todo("Block still life: [(0,0),(1,0),(0,1),(1,1)] remains unchanged after one generation");

  it.todo("Blinker oscillator: vertical [(0,0),(0,1),(0,2)] becomes horizontal [(-1,1),(0,1),(1,1)]");

  it.todo("Blinker oscillator: horizontal [(-1,1),(0,1),(1,1)] returns to vertical [(0,0),(0,1),(0,2)] (period 2)");

  it.todo("should handle negative coordinates: blinker centered at origin produces cells with negative x (e.g. (-1,1))");
});
